# Add a bypass rule to exclude specific traffic from being tunnelled
# Common use: internal DNS servers, Windows Update (already excluded by default)

$bypassRule = @{
    '@odata.type' = '#microsoft.graph.networkaccess.privateAccessForwardingRule'
    action = 'bypass'
    destinations = @(
        @{
            '@odata.type' = '#microsoft.graph.networkaccess.fqdnForwardingRule'
            value = 'internal-dns.corp.contoso.com'
        },
        @{
            '@odata.type' = '#microsoft.graph.networkaccess.ipSubnetForwardingRule'
            value = '192.168.100.0'
            prefixSize = 24
            protocol = 'TCP'
            ports = @('53')
        }
    )
} | ConvertTo-Json -Depth 6

# Attach bypass rule to the Private Access profile
Invoke-MgGraphRequest -Method POST `
  -Uri "https://graph.microsoft.com/beta/networkAccess/forwardingProfiles/$profileId/policies" `
  -Body $bypassRule

# There is no native Terraform resource for GSA forwarding profiles yet (2024 preview)
# Use azapi_resource to call the Graph API directly via Terraform

resource "azapi_resource" "gsa_internet_profile" {
  type      = "Microsoft.NetworkAccess/forwardingProfiles@2023-01-01-preview"
  name      = "internet-forwarding-profile"
  parent_id = "/providers/Microsoft.NetworkAccess"

  body = jsonencode({
    properties = {
      trafficForwardingType = "internet"
      state                 = "enabled"
    }
  })
}

# Alternative: use null_resource + local-exec to call Graph API
resource "null_resource" "enable_m365_profile" {
  provisioner "local-exec" {
    command = <<-CMD
      az rest --method PATCH \
        --url "https://graph.microsoft.com/beta/networkAccess/forwardingProfiles" \
        --body '{"trafficForwardingType":"microsoft365","state":"enabled"}'
    CMD
  }
}
